import React from "react";

export default function Sidebar({setTab}){

  return(

    <div className="sidebar">

      <h2>CampusBeacon</h2>

      <button onClick={()=>setTab("feed")}>
        Feed
      </button>

      <button onClick={()=>setTab("lost")}>
        Post Lost Item
      </button>

      <button onClick={()=>setTab("found")}>
        Post Found Item
      </button>

    </div>

  );

}
